var model = function() {

  // ── City level ───────────────────────────────────────────────
  // One city; its "freshness bias" is drawn once per model call.
  var cityPrior = beta({a: 0.25, b: 0.25});

  // ── Store level (memoised by store id) ───────────────────────
  // Each store is "fresh" with prob cityPrior → Beta(0.1, 0.3) params
  //                 "rotten" otherwise          → Beta(0.3, 0.1) params
  var storeBetaParams = mem(function(storeId) {
    return flip(cityPrior)
      ? {a: 0.1, b: 0.3}   // fresh store
      : {a: 0.3, b: 0.1};  // rotten store
  });

  // ── Barrel level (memoised by store × barrel id) ─────────────
  // Each barrel draws its own pRotten from the store's Beta.
  var barrelPRotten = mem(function(storeId, barrelId) {
    return beta(storeBetaParams(storeId));
  });

  // Helper: n iid Bernoulli draws from a barrel
  var barrel = function(storeId, barrelId, n) {
    var p = barrelPRotten(storeId, barrelId);
    return repeat(n, function() { return flip(p); });
  };

  // ── Observation ───────────────────────────────────────────────
  // Store 1, barrel 1: observe 7 rotten out of 10.
  var p1 = barrelPRotten('store1', 'barrel1');
  observe(Binomial({n: 10, p: p1}), 7);

  // ── Query ─────────────────────────────────────────────────────
  // Different store (store2) in the SAME city → shares cityPrior.
  // Draw a fresh barrel from that store and count rotten apples.
  var p2 = barrelPRotten('store2', 'barrel1');
  return binomial({n: 10, p: p2});
};

Infer({method: 'MCMC', samples: 5000, lag: 100}, model);

