  let vocab = ['dogs', 'cats', 'chase', 'sleep', 'stop'];

  var wordToDistribution = mem(function(word) {
    return dirichletDrift({alpha: ones([vocab.length, 1]), concentration: 10})
  })

  var transition = function(word) {
    return categorical({ps: wordToDistribution(word), vs: vocab})
  }

  // Recursively emit words starting from `word` until 'stop' is sampled.
  // Returns the list of non-stop words emitted (including the seed word).
  var generateSentence = function(word) {
    var nextWord = transition(word)
    if (nextWord === 'stop') {
      return [word]
    } else {
      return [word].concat(generateSentence(nextWord))
    }
  }

  // Observed sentence: "dogs chase cats"
  // Under the bigram model this means:
  //   dogs  -> chase
  //   chase -> cats
  //   cats  -> stop
  // Starting generation from the first word 'dogs':
  condition(_.isEqual(generateSentence('dogs'), ['dogs', 'chase', 'cats']))

  // Return the posterior predictive next-word distribution after 'chase'
  return transition('chase')
})

